#include <stdio.h>
#include <stdlib.h>
#include <string.h>

long long countCoinCombinations(int target, int *coins, int n) {
    long long *dp = (long long *)calloc(target + 1, sizeof(long long));
    dp[0] = 1;
    for (int i = 0; i < n; ++i) {
        int c = coins[i];
        for (int j = c; j <= target; ++j) {
            dp[j] += dp[j - c];
        }
    }
    long long ans = dp[target];
    free(dp);
    return ans;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int target;
        scanf("%d", &target);
        // consume the rest of the line after target
        int ch = getchar();
        while (ch != '\n' && ch != EOF) ch = getchar();
        char line[20000];
        if (!fgets(line, sizeof(line), stdin)) line[0] = '\0';
        int coins[305];
        int n = 0;
        char *token = strtok(line, " \t\n\r");
        while (token) {
            coins[n++] = atoi(token);
            token = strtok(NULL, " \t\n\r");
        }
        printf("%lld\n", countCoinCombinations(target, coins, n));
    }
    return 0;
}

