import java.io.*;
import java.util.*;

public class Main {
    private static long countCoinCombinations(int target, int[] coins) {
        long[] dp = new long[target + 1];
        dp[0] = 1;
        for (int c : coins) {
            for (int j = c; j <= target; ++j) dp[j] += dp[j - c];
        }
        return dp[target];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            int target = Integer.parseInt(br.readLine().trim());
            String line = br.readLine();
            if (line == null) line = "";
            StringTokenizer st = new StringTokenizer(line);
            List<Integer> list = new ArrayList<>();
            while (st.hasMoreTokens()) list.add(Integer.parseInt(st.nextToken()));
            int[] coins = list.stream().mapToInt(Integer::intValue).toArray();
            out.append(countCoinCombinations(target, coins)).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def countCoinCombinations(target, coins):
    dp = [0] * (target + 1)
    dp[0] = 1
    for c in coins:
        for j in range(c, target + 1):
            dp[j] += dp[j - c]
    return dp[target]

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        target = int(next(it))
        line = next(it, "")
        coins = list(map(int, line.split())) if line else []
        out.append(str(countCoinCombinations(target, coins)))
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

